const staticData = $getWorkflowStaticData('global');
const incoming = $input.first().json;
const body = incoming.body || incoming;
const subscription = body.subscription || body;

if (!subscription?.endpoint || !subscription?.keys?.p256dh || !subscription?.keys?.auth) {
  throw new Error('Missing push subscription endpoint or keys.');
}

staticData.subscriptions = Array.isArray(staticData.subscriptions) ? staticData.subscriptions : [];

const existingIndex = staticData.subscriptions.findIndex((saved) => saved.subscription?.endpoint === subscription.endpoint);
const savedSubscription = {
  subscription,
  userAgent: body.userAgent || incoming.headers?.['user-agent'] || null,
  appUrl: body.appUrl || null,
  updatedAt: new Date().toISOString(),
};

if (existingIndex >= 0) {
  staticData.subscriptions[existingIndex] = {
    ...staticData.subscriptions[existingIndex],
    ...savedSubscription,
  };
} else {
  staticData.subscriptions.push({
    ...savedSubscription,
    createdAt: new Date().toISOString(),
  });
}

return [{ json: { ok: true, saved: true, subscriptions: staticData.subscriptions.length } }];

const VAPID_PUBLIC_KEY = 'BOgNDXzC0mNLDzz-D_IxjYrBh4jEtQ-Mh87iw9IIeJWg3--CS9pU5TJVWjDH35tXNzNm25hwd_mnOmdAIElaySI';
const VAPID_PRIVATE_KEY = 'PASTE_VAPID_PRIVATE_KEY_HERE';
const SEND_SECRET = 'PASTE_SEND_SECRET_HERE';
const SUBJECT = 'mailto:tom@refindcommerce.com';

const incoming = $input.first().json;
const body = incoming.body || {};
const headers = incoming.headers || {};
const suppliedSecret = body.secret || headers['x-refind-push-secret'] || headers['X-ReFind-Push-Secret'];

if (!SEND_SECRET || SEND_SECRET === 'PASTE_SEND_SECRET_HERE' || suppliedSecret !== SEND_SECRET) {
  throw new Error('Invalid push secret.');
}

if (!VAPID_PRIVATE_KEY || VAPID_PRIVATE_KEY === 'PASTE_VAPID_PRIVATE_KEY_HERE') {
  throw new Error('Add the VAPID private key to this Code node before activating.');
}

const staticData = $getWorkflowStaticData('global');
const subscriptions = Array.isArray(staticData.subscriptions) ? staticData.subscriptions : [];

if (!subscriptions.length) {
  return [{ json: { ok: true, sent: 0, reason: 'No push subscriptions saved yet.' } }];
}

function base64UrlToBytes(value) {
  const base64 = `${value}${'='.repeat((4 - (value.length % 4)) % 4)}`.replace(/-/g, '+').replace(/_/g, '/');
  return Uint8Array.from(Buffer.from(base64, 'base64'));
}

function bytesToBase64Url(bytes) {
  return Buffer.from(bytes).toString('base64').replace(/=/g, '').replace(/\+/g, '-').replace(/\//g, '_');
}

function textToBase64Url(value) {
  return bytesToBase64Url(Buffer.from(value));
}

const webcrypto = globalThis.crypto?.subtle
  ? globalThis.crypto
  : require('crypto').webcrypto;

async function createVapidJwt(audience) {
  const publicBytes = base64UrlToBytes(VAPID_PUBLIC_KEY);
  const privateKey = await webcrypto.subtle.importKey(
    'jwk',
    {
      kty: 'EC',
      crv: 'P-256',
      x: bytesToBase64Url(publicBytes.slice(1, 33)),
      y: bytesToBase64Url(publicBytes.slice(33, 65)),
      d: VAPID_PRIVATE_KEY,
      ext: true,
    },
    { name: 'ECDSA', namedCurve: 'P-256' },
    false,
    ['sign']
  );

  const header = textToBase64Url(JSON.stringify({ typ: 'JWT', alg: 'ES256' }));
  const payload = textToBase64Url(JSON.stringify({
    aud: audience,
    exp: Math.floor(Date.now() / 1000) + 12 * 60 * 60,
    sub: SUBJECT,
  }));
  const unsignedToken = `${header}.${payload}`;
  const signature = await webcrypto.subtle.sign(
    { name: 'ECDSA', hash: 'SHA-256' },
    privateKey,
    Buffer.from(unsignedToken)
  );

  return `${unsignedToken}.${bytesToBase64Url(new Uint8Array(signature))}`;
}

const items = [];
const expiredEndpoints = new Set();

for (const saved of subscriptions) {
  const endpoint = saved.subscription?.endpoint;
  if (!endpoint) continue;

  const audience = new URL(endpoint).origin;
  const token = await createVapidJwt(audience);
  items.push({
    json: {
      endpoint,
      ttl: '2419200',
      authorization: `vapid t=${token}, k=${VAPID_PUBLIC_KEY}`,
    },
  });
}

staticData.lastPushAttemptAt = new Date().toISOString();
staticData.expiredEndpoints = [...expiredEndpoints];

return items;
